{"content": "# nanobot Skills 一键安装脚本
# 适用于 Windows PowerShell
# 运行前请确保有管理员权限（部分安装需要）

Write-Host "🐈 nanobot Skills 安装脚本" -ForegroundColor Cyan
Write-Host "================================" -ForegroundColor Cyan
Write-Host ""

# 检测系统
$isWSL = (wsl --status 2>$null) -and $true
$isWindows = -not $isWSL

Write-Host "系统检测：$(if ($isWSL) { 'WSL' } else { 'Windows' })" -ForegroundColor Yellow
Write-Host ""

# 1. GitHub CLI (gh)
Write-Host "🐙 安装 GitHub CLI..." -ForegroundColor Green
if (Get-Command gh -ErrorAction SilentlyContinue) {
    Write-Host "  ✓ gh 已安装：$(gh --version | Select-Object -First 1)" -ForegroundColor Gray
} else {
    Write-Host "  ⚡ 使用 winget 安装 gh..." -ForegroundColor Gray
    winget install --id GitHub.cli --silent --accept-package-agreements --accept-source-agreements
    if ($LASTEXITCODE -eq 0) {
        Write-Host "  ✓ gh 安装成功" -ForegroundColor Green
    } else {
        Write-Host "  ✗ gh 安装失败，请手动安装：https://cli.github.com/" -ForegroundColor Red
    }
}
Write-Host ""

# 2. Summarize CLI
Write-Host "🧾 安装 Summarize CLI..." -ForegroundColor Green
if (Get-Command summarize -ErrorAction SilentlyContinue) {
    Write-Host "  ✓ summarize 已安装" -ForegroundColor Gray
} else {
    Write-Host "  ⚡ 尝试使用 cargo 安装..." -ForegroundColor Gray
    if (Get-Command cargo -ErrorAction SilentlyContinue) {
        cargo install --git https://github.com/steipete/summarize.git
        if ($LASTEXITCODE -eq 0) {
            Write-Host "  ✓ summarize 安装成功" -ForegroundColor Green
        } else {
            Write-Host "  ✗ summarize 安装失败" -ForegroundColor Red
        }
    } else {
        Write-Host "  ⚠ cargo 未安装，请先安装 Rust: https://rustup.rs/" -ForegroundColor Yellow
        Write-Host "  或使用备用方案：pip install summarize-cli (如果有)" -ForegroundColor Gray
    }
}
Write-Host ""

# 3. tmux (仅 WSL/Linux/macOS)
Write-Host "🧵 安装 tmux..." -ForegroundColor Green
if ($isWSL) {
    if (wsl which tmux 2>$null) {
        Write-Host "  ✓ tmux 已在 WSL 中安装" -ForegroundColor Gray
    } else {
        Write-Host "  ⚡ 在 WSL 中安装 tmux..." -ForegroundColor Gray
        wsl sudo apt-get update && wsl sudo apt-get install -y tmux
        if ($LASTEXITCODE -eq 0) {
            Write-Host "  ✓ tmux 安装成功" -ForegroundColor Green
        } else {
            Write-Host "  ✗ tmux 安装失败" -ForegroundColor Red
        }
    }
} else {
    Write-Host "  ⚠ Windows 原生不支持 tmux，建议使用 WSL" -ForegroundColor Yellow
    Write-Host "  启用 WSL: wsl --install" -ForegroundColor Gray
}
Write-Host ""

# 验证安装
Write-Host "================================" -ForegroundColor Cyan
Write-Host "📋 安装验证:" -ForegroundColor Cyan
Write-Host ""

$tools = @()
if (Get-Command gh -ErrorAction SilentlyContinue) {
    $tools += "gh: ✓"
} else {
    $tools += "gh: ✗"
}

if (Get-Command summarize -ErrorAction SilentlyContinue) {
    $tools += "summarize: ✓"
} else {
    $tools += "summarize: ✗"
}

if ($isWSL -and (wsl which tmux 2>$null)) {
    $tools += "tmux (WSL): ✓"
} elseif ($isWSL) {
    $tools += "tmux (WSL): ✗"
} else {
    $tools += "tmux: N/A (Windows)"
}

foreach ($tool in $tools) {
    Write-Host "  $tool" -ForegroundColor $(if ($tool -like "*✓*") { "Green" } elseif ($tool -like "*✗*") { "Red" } else { "Gray" })
}

Write-Host ""
Write-Host "================================" -ForegroundColor Cyan
Write-Host "完成后请重启 nanobot 以启用新 skills" -ForegroundColor Yellow
Write-Host ""
