"""
抢票技能 (Ticket Snatcher)
自动监控余票并生成订单（不付款）

功能：
1. 监控余票状态
2. 自动下单生成订单
3. 支持多个票务平台
4. 飞书消息通知
5. 支持多账号/多场次

注意：本技能仅生成订单，不自动付款
"""

import urllib.request
import urllib.error
import json
import sys
import os
import time
import argparse
import hashlib
import random
from datetime import datetime
from typing import Optional, Dict, List

# 设置输出编码
if sys.platform == 'win32':
    sys.stdout.reconfigure(encoding='utf-8')

# ============ 配置区域 ============

# 输出目录
OUTPUT_DIR = r"C:\Users\zyc\.nanobot\workspace\output\tickets"

# 日志文件
LOG_FILE = os.path.join(OUTPUT_DIR, "ticket_log.json")

# 飞书 Webhook (可选，用于通知)
FEISHU_WEBHOOK = os.environ.get('FEISHU_WEBHOOK', '')

# 默认请求头
DEFAULT_HEADERS = {
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    'Accept': 'application/json, text/plain, */*',
    'Accept-Language': 'zh-CN,zh;q=0.9,en;q=0.8',
    'Content-Type': 'application/json',
}

# ============ 工具函数 ============

def ensure_output_dir():
    """确保输出目录存在"""
    if not os.path.exists(OUTPUT_DIR):
        os.makedirs(OUTPUT_DIR)

def log_action(action: str, details: dict):
    """记录操作日志"""
    ensure_output_dir()

    log_entry = {
        'timestamp': datetime.now().isoformat(),
        'action': action,
        'details': details
    }

    # 读取现有日志
    logs = []
    if os.path.exists(LOG_FILE):
        try:
            with open(LOG_FILE, 'r', encoding='utf-8') as f:
                logs = json.load(f)
        except:
            logs = []

    # 添加新日志
    logs.append(log_entry)

    # 保存日志（保留最近 100 条）
    logs = logs[-100:]
    with open(LOG_FILE, 'w', encoding='utf-8') as f:
        json.dump(logs, f, ensure_ascii=False, indent=2)

def send_feishu_notification(title: str, content: str, webhook: str = None):
    """发送飞书通知"""
    if not webhook and not FEISHU_WEBHOOK:
        return

    webhook_url = webhook or FEISHU_WEBHOOK

    payload = {
        "msg_type": "post",
        "content": {
            "post": {
                "zh_cn": {
                    "title": title,
                    "content": [
                        [
                            {
                                "tag": "text",
                                "text": content
                            }
                        ]
                    ]
