def smart_truncate(text: str, max_length: int = 60) -> str:
    """智能截断文本，确保在标点处断开"""
    if len(text) <= max_length:
        return text

    # 尝试在标点处断开
    for punct in ['。', '！', '？', '；', ',', '.', '!', '?']:
        pos = text[:max_length].rfind(punct)
        if pos > max_length * 0.6:  # 在 60% 位置之后
            return text[:pos+1]

    # 没有合适标点，直接截断
    return text[:max_length-2] + '...'


